1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	function calculatePremium(items: any[]): number {
13	  let basePremium = 0;
14	  for (const item of items) {
15	    basePremium += BASE_PREMIUMS[item.type];
16	  }
17	  return basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
18	}
19	
20	export function processScenario(scenario: any): unknown {
21	  const { items } = scenario.steps[0];
22	  const premium = calculatePremium(items);
23	
24	  return { results: [{ premium }] };
25	}
